export type ApplicationKind = 'git' | 'github' | 'uploaded' | null;
export type Application = {
    id: string;
    title: string;
    description: string;
    kind: ApplicationKind;
    baseImage: string;
    buildWorkingPath?: string;
    buildScript?: string;
    buildOutputPath?: string;
    buildEnvironmentVariables?: Record<string, string>;
    versions?: ApplicationVersion[];
    createdAt?: string;
    updatedAt?: string;
};
export type ApplicationVersion = {
    name?: string;
    version?: string;
    applicationId: string;
    buildId: string;
    applicationSpecifier: string;
    publishedAt: string;
};
export type ApplicationBuild = {
    id: string;
    applicationId: string;
    index: number;
    state: 'pending' | 'building' | 'success' | 'failure' | 'failed' | 'cancelled';
    logs: string[];
    scheduledAt?: string;
    startedAt?: string;
    finishedAt?: string;
};
export type CreateApplicationRequest = {
    kind: 'uploaded';
    title: string;
    description?: string;
    baseImage: string;
    baseImageRegistryAuth: string;
    buildWorkingPath: string;
    buildScript: string;
    buildOutputPath: string;
    buildEnvironmentVariables?: Record<string, string>;
};
